/** Strip dark./light. prefix from color/gradient token names */
function stripModePrefix(name: string, type: string): string {
  if (type === 'color' || type === 'gradient') {
    return name.replace(/^(dark|light)\./, '');
  }
  return name;
}

export async function seedTokens(
  db: any,
  ctx: { designSystems: { plasmaTest: any } },
) {
  const { plasmaTest } = ctx.designSystems;

  // Deduplicate after stripping dark./light. prefix from color/gradient tokens
  const seen = new Set<string>();
  const deduped = TOKEN_DEFS.filter(t => {
    const name = stripModePrefix(t.name, t.type);
    if (seen.has(name)) return false;
    seen.add(name);
    return true;
  });

  const tokenRows = deduped.map(t => ({
    designSystemId: plasmaTest.id,
    name: stripModePrefix(t.name, t.type),
    type: t.type,
    displayName: t.displayName,
    description: t.description,
    enabled: t.enabled,
  }));

  const BATCH_SIZE = 500;
  const allInserted: any[] = [];
  for (let i = 0; i < tokenRows.length; i += BATCH_SIZE) {
    const batch = tokenRows.slice(i, i + BATCH_SIZE);
    const inserted = await db.insert(schema.tokens).values(batch).returning();
    allInserted.push(...inserted);
  }

  const tokenMap: Record<string, any> = {};
  for (const row of allInserted) {
    tokenMap[row.name] = row;
  }

  console.log(`  tokens: ${allInserted.length} rows`);
  return tokenMap;
}